// ENTWURF - erzeugt nur einen Plan, keine Rollo-Kommandos.
// Startwerte nach Beobachtung anpassen.
const cfg = {
    shadeOnW: 2500,       // Beschattung aktiv ab PV-Leistung
    shadeOffW: 1200,      // später für Hysterese: unter diesem Wert lösen
    shadePos: 50,
    openPos: 100,
    eastStartHour: 7,
    eastEndHour: 13,
    westEndHour: 20.5,
    randomDelayMinSec: 30,
    randomDelayMaxSec: 480
};

function decodeSenecValue(data) {
    if (data === undefined || data === null) return NaN;
    if (typeof data === 'number') return data;
    if (typeof data !== 'string') return NaN;
    const tmp = data.split('_');
    if (tmp.length < 2) return Number(data);
    const type = tmp[0];
    const value = tmp[1];
    if (type === 'fl') {
        const buf = Buffer.from(value, 'hex');
        return Math.round(buf.readFloatBE(0) * 100) / 100;
    }
    if (['u8','u1','u3','u6'].includes(type)) return parseInt(value, 16);
    if (['i1','i3','i8'].includes(type)) return parseInt(value, 16);
    return Number(value);
}

const energy = msg.payload && msg.payload.ENERGY ? msg.payload.ENERGY : {};
const pvW = decodeSenecValue(energy.GUI_INVERTER_POWER);
const houseW = decodeSenecValue(energy.GUI_HOUSE_POW);
const gridW = decodeSenecValue(energy.GUI_GRID_POW);
const batteryW = decodeSenecValue(energy.GUI_BAT_DATA_POWER);
const batteryPct = decodeSenecValue(energy.GUI_BAT_DATA_FUEL_CHARGE);
const now = new Date();
const hour = now.getHours() + now.getMinutes() / 60;

let phase = 'none';
if (hour >= cfg.eastStartHour && hour < cfg.eastEndHour) phase = 'east';
else if (hour >= cfg.eastEndHour && hour < cfg.westEndHour) phase = 'west';

const sunny = pvW >= cfg.shadeOnW;
const plan = {
    ts: now.toISOString(),
    pvW, houseW, gridW, batteryW, batteryPct, sunny, phase, cfg,
    groups: {
        east: ['Kueche2','GaesteBad','Badezimmer','Arbeitszimmer2'],
        west: ['Schlafzimmer1','Schlafzimmer2','Wohnzimmer1','Wohnzimmer2']
    },
    actions: []
};

if (sunny && phase === 'east') {
    plan.actions.push({group:'east', target:cfg.shadePos, reason:'morgens starke Solarleistung'});
}
if (phase === 'west') {
    plan.actions.push({group:'east', target:cfg.openPos, reason:'Sonne ist auf Westseite gewechselt'});
    if (sunny) plan.actions.push({group:'west', target:cfg.shadePos, reason:'nachmittags starke Solarleistung'});
}

msg.payload = plan;
return msg;
